  ('social-worker-moex-05850', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '假設統計成績為鐘型分配，A同學Z分數⎜ ⎟為2，換言之，他約贏過多少百分比的同學？ ⎝ 標準差 ⎠', '["2.5%", "50.5%", "97.5%", "99.5%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05851', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '大仁哥與又青姐結婚了，他們預定生四個小孩，假設生男生女的機率各半，請問連續生四個男生的機率 是多少？', '["0.0625", "0.5", "0.0005", "0.8"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05852', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '質化田野研究中，與受觀察者建立友善關係是絕對必要的，有關建立友善關係，下列敘述何者錯誤？', '["不要與你的受訪者爭辯", "放鬆且適切地進入觀察情境中", "當個專心傾聽者", "不能揭露研究人員的真實身分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05853', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關紮根理論（grounded theory）進行資料編碼的程序，何者正確？', '["開放性編碼 → 主軸性編碼 → 選擇性編碼", "開放性編碼 → 選擇性編碼 → 主軸性編碼", "選擇性編碼 → 開放性編碼 → 主軸性編碼", "主軸性編碼 → 選擇性編碼 → 開放性編碼"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05854', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關抽樣的敘述，何者錯誤？', '["方便抽樣係研究者基於自己的便利，從母體中觀察某些就近方便取得的樣本，可估計其抽樣誤差，適 合以統計方法對母體進行統計推論", "機率抽樣所得到的樣本可利用機率去探討樣本特性，推論抽樣誤差", "簡單隨機抽樣是指抽樣母體中所有可能被抽出的樣本組，被抽出的機率均相等", "採用普查方法蒐集資料，不需要用統計方法推估母體參數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05855', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '從事量化研究時，研究者需要先設定研究假設，再透過資料的蒐集及分析來驗證或否證研究假設。下列 何者非建構假設時應該考慮的因素？', '["要以理論來引導", "需先取得權威專家的認可", "陳述要明確", "要以實證為基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05856', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '假想某研究者正在進行某直轄市的「老人生活狀況調查」，下列何種方法最能精準地反映出該市老人的 生活狀況？', '["寄發網路問卷，並以滾雪球的方式請受訪者將此問卷轉寄給認識者，轉寄越多獲獎越大", "按戶籍名冊以「按數量成比例的機率抽樣法（簡稱PPS）」抽出受訪者並進行面訪", "隨機抽出市內的30個里，針對這30個里的全體里民發放問卷施測", "請工讀生在市內的各醫療院所及大賣場針對看病或購物的民眾進行面對面的訪問"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05857', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關操作性定義（operational definition）的敘述，何者為其主要目的？', '["確定變項的測量尺度以選擇適當的統計方法", "說明一份研究的研究架構", "幫助研究者檢驗測量工具的信度與效度", "將抽象的概念予以實體化，以利對此概念進行系統性的觀察與測量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05858', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關「效度」的敘述，何者錯誤？', '["效度是測量品質的方法之一", "效度是指測量工具正確地反映出它要測量的概念", "內容效度是指一項測量涵蓋了一個概念所含意義範圍的程度", "信度是效度的充分條件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05859', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '結構性訪談（structured interviews）與質性訪談（qualitative interviews）皆是質性資料蒐集方法之一，下 列敘述何者錯誤？', '["結構性訪談有完整的擬詢問題（腳本）清單，質性訪談則無完整的擬詢問題（腳本）清單", "兩類訪談皆多以開放性問題（open-ended questions）來進行訪談", "質性訪談者不會刻意維持訪談行為與風度的一致性，而結構性訪談者則儘量保持行為與風度的一致性", "質性訪談者會希望受訪者用自己的語彙（words）與觀點來描述/回應提問"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
